Javascript.isReadOnly:
var reasonForReferral = Services.getValue(ReasonForReferral.dataBinding);
var reasonValueTest = Services.getValue( REF_DATA_XPATH + "/ReasonForReferralList/ReasonForReferral[./Description = " + ReasonForReferral.dataBinding + "]/Value" );
var whoFailedToLodgeQuestionnaire = Services.getValue(WhoFailedToLodgeQuestionnaire.dataBinding);
var whoValueTest = Services.getValue( REF_DATA_XPATH + "/WhoFailedToLodgeQuestionnaireList/WhoFailedToLodgeQuestionnaire[./Description = " + WhoFailedToLodgeQuestionnaire.dataBinding + "]/Value" );
if (reasonForReferral == "ALL" || reasonValueTest == "ALL")
{
	return true;
}
else if (whoFailedToLodgeQuestionnaire == "OTH" || whoValueTest == "OTH")
{
	return false;
}
else
{
	return true;
}
